-- ============================================================
  -- lilluucore — Полный дамп базы данных (SQL)
  -- Дата: 2026-05-05T16:56:55.800Z
  -- PostgreSQL
  -- ============================================================

  SET client_encoding = 'UTF8';
  SET standard_conforming_strings = on;
  SET check_function_bodies = false;
  SET client_min_messages = warning;
  SET row_security = off;

  -- ============================================================
  -- DDL: Создание таблиц
  -- ============================================================

  CREATE TABLE IF NOT EXISTS users (
      id character varying NOT NULL,
      email text NOT NULL,
      password_hash text NOT NULL,
      first_name text NOT NULL,
      last_name text NOT NULL,
      plan text NOT NULL DEFAULT 'free',
      role text NOT NULL DEFAULT 'user',
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT users_pkey PRIMARY KEY (id),
      CONSTRAINT users_email_unique UNIQUE (email)
  );

  CREATE TABLE IF NOT EXISTS user_settings (
      user_id character varying NOT NULL,
      theme text NOT NULL DEFAULT 'dark',
      notifications boolean NOT NULL DEFAULT true,
      email_notifications boolean NOT NULL DEFAULT true,
      avatar_url text,
      db_access_locked boolean NOT NULL DEFAULT false,
      db_lock_reason text,
      seo_settings text NOT NULL DEFAULT '{}',
      updated_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT user_settings_pkey PRIMARY KEY (user_id),
      CONSTRAINT user_settings_user_id_users_id_fk FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS sites (
      id character varying NOT NULL,
      user_id character varying NOT NULL,
      name text NOT NULL,
      subdomain text NOT NULL,
      business_type text NOT NULL,
      status text NOT NULL DEFAULT 'DRAFT',
      published_url text,
      global_styles text NOT NULL DEFAULT '{}',
      frozen boolean NOT NULL DEFAULT false,
      frozen_reason text,
      frozen_by character varying,
      frozen_at timestamp without time zone,
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      updated_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT sites_pkey PRIMARY KEY (id),
      CONSTRAINT sites_subdomain_unique UNIQUE (subdomain),
      CONSTRAINT sites_user_id_users_id_fk FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS pages (
      id character varying NOT NULL,
      site_id character varying NOT NULL,
      name text NOT NULL,
      slug text NOT NULL,
      position integer NOT NULL DEFAULT 0,
      meta text NOT NULL DEFAULT '{}',
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT pages_pkey PRIMARY KEY (id),
      CONSTRAINT pages_site_id_sites_id_fk FOREIGN KEY (site_id) REFERENCES sites(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS blocks (
      id character varying NOT NULL,
      site_id character varying NOT NULL,
      page_id character varying,
      type text NOT NULL,
      position integer NOT NULL DEFAULT 0,
      row_id text,
      content text NOT NULL DEFAULT '{}',
      styles text NOT NULL DEFAULT '{}',
      visible boolean NOT NULL DEFAULT true,
      width integer NOT NULL DEFAULT 100,
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT blocks_pkey PRIMARY KEY (id),
      CONSTRAINT blocks_site_id_sites_id_fk FOREIGN KEY (site_id) REFERENCES sites(id) ON DELETE CASCADE,
      CONSTRAINT blocks_page_id_pages_id_fk FOREIGN KEY (page_id) REFERENCES pages(id) ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS notifications (
      id integer NOT NULL,
      user_id character varying NOT NULL,
      type text NOT NULL DEFAULT 'info',
      title text NOT NULL,
      message text NOT NULL,
      read boolean NOT NULL DEFAULT false,
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT notifications_pkey PRIMARY KEY (id),
      CONSTRAINT notifications_user_id_users_id_fk FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE SEQUENCE IF NOT EXISTS notifications_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
  ALTER SEQUENCE notifications_id_seq OWNED BY notifications.id;

  CREATE TABLE IF NOT EXISTS chat_messages (
      id integer NOT NULL,
      from_user_id character varying NOT NULL,
      to_user_id character varying NOT NULL,
      message text NOT NULL,
      image_url text,
      ticket_id character varying,
      read boolean NOT NULL DEFAULT false,
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT chat_messages_pkey PRIMARY KEY (id),
      CONSTRAINT chat_messages_from_user_id_users_id_fk FOREIGN KEY (from_user_id) REFERENCES users(id) ON DELETE CASCADE,
      CONSTRAINT chat_messages_to_user_id_users_id_fk FOREIGN KEY (to_user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE SEQUENCE IF NOT EXISTS chat_messages_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
  ALTER SEQUENCE chat_messages_id_seq OWNED BY chat_messages.id;

  CREATE TABLE IF NOT EXISTS form_submissions (
      id integer NOT NULL,
      site_id character varying NOT NULL,
      block_id character varying,
      form_title text NOT NULL DEFAULT 'Заявка',
      data text NOT NULL,
      submitter_ip text,
      created_at timestamp without time zone NOT NULL DEFAULT now(),
      CONSTRAINT form_submissions_pkey PRIMARY KEY (id),
      CONSTRAINT form_submissions_site_id_sites_id_fk FOREIGN KEY (site_id) REFERENCES sites(id) ON DELETE CASCADE
  );

  CREATE SEQUENCE IF NOT EXISTS form_submissions_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
  ALTER SEQUENCE form_submissions_id_seq OWNED BY form_submissions.id;

  CREATE TABLE IF NOT EXISTS site_analytics (
      id integer NOT NULL,
      site_id character varying NOT NULL,
      date text NOT NULL,
      views integer NOT NULL DEFAULT 0,
      clicks integer NOT NULL DEFAULT 0,
      unique_visitors integer NOT NULL DEFAULT 0,
      new_registrations integer NOT NULL DEFAULT 0,
      avg_session_sec integer NOT NULL DEFAULT 0,
      CONSTRAINT site_analytics_pkey PRIMARY KEY (id),
      CONSTRAINT site_analytics_site_id_sites_id_fk FOREIGN KEY (site_id) REFERENCES sites(id) ON DELETE CASCADE
  );

  CREATE SEQUENCE IF NOT EXISTS site_analytics_id_seq AS integer START WITH 1 INCREMENT BY 1 NO MINVALUE NO MAXVALUE CACHE 1;
  ALTER SEQUENCE site_analytics_id_seq OWNED BY site_analytics.id;

  -- ============================================================
